// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  const isSmall = width < 420;
  const isMobile = width < 768;
  const isDesktop = width >= 1024;

  const containerMaxWidth = isDesktop ? 520 : isMobile ? 520 : "100%";

  const [query, setQuery] = useState(
    "Total borne 10 entre\nenfant noir chez le boss"
  );

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.page}>
        <View style={[styles.container, { maxWidth: containerMaxWidth }]}>
          {/* ✅ HEADER: remove big capsule; match mock (clean header on background) */}
          <View style={styles.headerRow}>
            <Image
              source={nalicoreLogo}
              style={[styles.logo, { width: isSmall ? 175 : 210 }]}
              resizeMode="contain"
            />

            {/* ✅ Tagline EXACTLY like mock (2 lines) */}
            <Text
              style={[
                styles.tagline,
                {
                  fontSize: isSmall ? 15 : 16,
                  lineHeight: isSmall ? 20 : 22,
                },
              ]}
              numberOfLines={2}
            >
              Natural Address{"\n"}Location Infrastructure
            </Text>
          </View>

          {/* Search + Resolve */}
          <View style={styles.searchBar}>
            <View style={styles.searchLeft}>
              <Text style={styles.searchIcon}>⌕</Text>

              <TextInput
                value={query}
                onChangeText={setQuery}
                style={[
                  styles.searchInput,
                  {
                    fontSize: isSmall ? 15 : 16,
                    lineHeight: isSmall ? 20 : 22,
                  },
                ]}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                multiline
                numberOfLines={2}
                scrollEnabled={false}
                textAlignVertical="center"
                underlineColorAndroid="transparent"
              />
            </View>

            <View style={styles.searchDivider} />

            <TouchableOpacity
              activeOpacity={0.9}
              style={[styles.resolveBtn, { width: isSmall ? 120 : 135 }]}
              onPress={onResolve}
            >
              <Text style={[styles.resolveText, { fontSize: isSmall ? 16 : 17 }]}>
                Resolve
              </Text>
            </TouchableOpacity>
          </View>

          {/* Card */}
          <View style={styles.card}>
            <Text style={[styles.cardTitle, { fontSize: isSmall ? 20 : 22 }]}>
              Resolved Address
            </Text>

            <View style={styles.cardDivider} />

            <Row label="Quartier:" value={resolved.quartier} isSmall={isSmall} />
            <Row label="Secteur:" value={resolved.secteur} isSmall={isSmall} />
            <Row label="Sous-secteur:" value={resolved.sousSecteur} isSmall={isSmall} />
            <Row label="Entrée:" value={resolved.entree} isSmall={isSmall} />
            <Row label="Lieu:" value={resolved.lieu} isSmall={isSmall} />

            <View style={styles.row}>
              <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>
                BANOC:
              </Text>
              <View style={styles.banocPill}>
                <Text style={styles.banocText}>{resolved.banoc}</Text>
              </View>
            </View>

            <Row
              label="Latitude:"
              value={Number(resolved.latitude).toFixed(5)}
              isSmall={isSmall}
            />
            <Row
              label="Longitude:"
              value={Number(resolved.longitude).toFixed(5)}
              isSmall={isSmall}
            />

            <TouchableOpacity activeOpacity={0.9} style={styles.navBtn} onPress={onNavigate}>
              {/* ✅ Better pin, closer to mock */}
              <PinIcon />
              <Text style={[styles.navText, { fontSize: isSmall ? 18 : 19 }]}>
                Navigate to Location
              </Text>
            </TouchableOpacity>
          </View>
        </View>
      </View>
    </SafeAreaView>
  );
}

function Row({ label, value, isSmall }) {
  return (
    <View style={styles.row}>
      <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>{label}</Text>
      <Text style={[styles.value, { fontSize: isSmall ? 15 : 16 }]} numberOfLines={1}>
        {value}
      </Text>
    </View>
  );
}

/** ✅ Pin icon closer to mock (pin + inner hole) */
function PinIcon() {
  return (
    <View style={styles.pinBg}>
      <View style={styles.pinShape}>
        <View style={styles.pinHole} />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },

  page: {
    flex: 1,
    alignItems: "center",
    paddingTop: 14,
    paddingHorizontal: 14,
  },

  container: {
    width: "100%",
    paddingHorizontal: 0,
    paddingTop: 0,
  },

  /* ✅ Header now NOT inside a capsule */
  headerRow: {
    width: "100%",
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    paddingHorizontal: 6,
    marginBottom: 14,
    marginTop: 2,
  },

  logo: { height: 48 },

  tagline: {
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.62)",
    fontWeight: "500",
    maxWidth: 240,
  },

  searchBar: {
    width: "100%",
    height: 66,
    borderRadius: 18,
    overflow: "hidden",
    flexDirection: "row",
    backgroundColor: "rgba(255,255,255,0.65)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    marginBottom: 14,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.06,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 2 },
    }),
  },

  searchLeft: {
    flex: 1,
    paddingLeft: 42,
    paddingRight: 10,
    justifyContent: "center",
  },

  searchIcon: {
    position: "absolute",
    left: 16,
    top: 24,
    fontSize: 18,
    color: "rgba(15, 23, 42, 0.45)",
  },

  /* ✅ Make input NOT bold like your screenshot */
  searchInput: {
    fontWeight: "500",
    color: "#0F172A",
    paddingVertical: 0,
    height: 66,
    ...(Platform.OS === "web" ? { outlineStyle: "none" } : null),
  },

  searchDivider: { width: 1, backgroundColor: "rgba(15,23,42,0.08)" },

  resolveBtn: {
    height: 66,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
  },

  resolveText: {
    color: "#FFFFFF",
    fontWeight: "600",
    letterSpacing: 0.2,
  },

  card: {
    width: "100%",
    backgroundColor: "rgba(255,255,255,0.65)",
    borderRadius: 22,
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    padding: 18,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.08,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 3 },
    }),
  },

  cardTitle: {
    fontWeight: "700",
    color: "#0F172A",
    marginBottom: 10,
  },

  /* ✅ Add divider line like mock */
  cardDivider: {
    height: 1,
    backgroundColor: "rgba(15,23,42,0.08)",
    marginBottom: 14,
  },

  row: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: 10,
    gap: 10,
  },

  label: {
    width: 120,
    color: "rgba(15,23,42,0.55)",
    fontWeight: "500",
  },

  value: {
    flex: 1,
    color: "#0F172A",
    fontWeight: "600",
  },

  banocPill: {
    backgroundColor: "rgba(46,89,183,0.12)",
    borderRadius: 12,
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderWidth: 1,
    borderColor: "rgba(46,89,183,0.18)",
  },

  banocText: {
    color: "#2E59B7",
    fontSize: 14,
    fontWeight: "700",
    letterSpacing: 0.8,
  },

  navBtn: {
